#define THREADS 256
#define WIDTH 16  
#define HEIGHT 16 
#define ETA 0.3f       
#define MOMENTUM 0.3f  

#include <omp.h>
#include <stdio.h>
#include <stdlib.h>
#include "backprop.h"
#include <math.h>

#define ABS(x) (((x) > 0.0) ? (x) : (-(x)))

#define WM(i, j) weight_matrix[(j) + (i) * WIDTH]

void bpnn_layerforward_omp(float *input_cuda,
                           float *output_hidden_cuda,
                           float *input_hidden_cuda,
                           float *hidden_partial_sum,
                           int in,
                           int hid) 
{
    int num_blocks = in / BLOCK_SIZE;

    #pragma omp parallel for collapse(2) shared(input_cuda, output_hidden_cuda, input_hidden_cuda, hidden_partial_sum, in, hid, num_blocks)
    for (int by = 0; by < num_blocks; by++) {
        for (int ty = 0; ty < HEIGHT; ty++) {
            float input_node[HEIGHT];
            float weight_matrix[HEIGHT * WIDTH];

            int index_in = HEIGHT * by + ty + 1;

            if (ty == 0) {
                input_node[ty] = input_cuda[index_in];
            }

            #pragma omp barrier

            for (int tx = 0; tx < WIDTH; tx++) {
                int index = (hid + 1) * HEIGHT * by + (hid + 1) * ty + tx + 1 + (hid + 1);
                weight_matrix[ty * WIDTH + tx] = input_hidden_cuda[index];
            }

            #pragma omp barrier

            for (int tx = 0; tx < WIDTH; tx++) {
                weight_matrix[ty * WIDTH + tx] = weight_matrix[ty * WIDTH + tx] * input_node[ty];
            }

            #pragma omp barrier

            for (int i = 1; i <= HEIGHT; i = i * 2) {
                int power_two = i;

                if (ty % power_two == 0) {
                    for (int tx = 0; tx < WIDTH; tx++) {
                        weight_matrix[ty * WIDTH + tx] = weight_matrix[ty * WIDTH + tx] + weight_matrix[(ty + power_two/2) * WIDTH + tx];
                    }
                }

                #pragma omp barrier
            }

            for (int tx = 0; tx < WIDTH; tx++) {
                int index = (hid + 1) * HEIGHT * by + (hid + 1) * ty + tx + 1 + (hid + 1);
                input_hidden_cuda[index] = weight_matrix[ty * WIDTH + tx];
            }

            #pragma omp barrier

            if (ty == 0) {
                for (int tx = 0; tx < WIDTH; tx++) {
                    hidden_partial_sum[by * hid + tx] = weight_matrix[tx * WIDTH + ty];
                }
            }
        }
    }
}

void bpnn_adjust_weights_omp(float *delta,   
                             int hid,         
                             float *ly,      
                             int in,          
                             float *w,       
                             float *oldw)
{
    int num_blocks = in / BLOCK_SIZE;

    #pragma omp parallel for collapse(2) shared(delta, ly, w, oldw, hid, in, num_blocks)
    for (int by = 0; by < num_blocks; by++) {
        for (int ty = 0; ty < HEIGHT; ty++) {
            for (int tx = 0; tx < WIDTH; tx++) {
                int index = (hid + 1) * HEIGHT * by + (hid + 1) * ty + tx + 1 + (hid + 1);
                int index_y = HEIGHT * by + ty + 1;
                int index_x = tx + 1;

                float new_dw = ((ETA * delta[index_x] * ly[index_y]) + (MOMENTUM * oldw[index]));
                w[index] += new_dw;
                oldw[index] = new_dw;
            }

            #pragma omp barrier

            if (ty == 0 && by == 0) {
                for (int tx = 0; tx < WIDTH; tx++) {
                    int index_x = tx + 1;
                    float new_dw = ((ETA * delta[index_x]) + (MOMENTUM * oldw[index_x]));
                    w[index_x] += new_dw;
                    oldw[index_x] = new_dw;
                }
            }
        }
    }
}

